/* ============================================================
   loading.css — Spinner และ Skeleton Loading ใช้ร่วมกันทั้งระบบ
   ============================================================ */

.spinner {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  border: 4px solid var(--color-primary-light);
  border-top-color: var(--color-primary);
  animation: spin 700ms linear infinite;
}

.spinner.sm { width: 20px; height: 20px; border-width: 3px; }
.spinner.lg { width: 56px; height: 56px; border-width: 5px; }

@keyframes spin {
  to { transform: rotate(360deg); }
}

.loading-fullpage {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--space-4);
  background: var(--color-bg-canvas);
}

.loading-fullpage-label {
  color: var(--color-text-muted);
  font-size: var(--fs-small);
}

/* ---------- Skeleton ---------- */
.skeleton {
  background: linear-gradient(90deg, #EDEDEF 25%, #F5F5F6 37%, #EDEDEF 63%);
  background-size: 400% 100%;
  animation: skeleton-shine 1.4s ease infinite;
  border-radius: var(--radius-sm);
}

@keyframes skeleton-shine {
  0% { background-position: 100% 50%; }
  100% { background-position: 0 50%; }
}

.skeleton-line {
  height: 14px;
  margin-bottom: var(--space-2);
  width: 100%;
}

.skeleton-line.w-60 { width: 60%; }
.skeleton-line.w-40 { width: 40%; }

.skeleton-card {
  height: 96px;
  border-radius: var(--radius-md);
}

.skeleton-row {
  height: 44px;
  margin-bottom: var(--space-2);
  border-radius: var(--radius-sm);
}
